48	/// Print the fields of a `$VN(R|W)RG,<id>,<f1>,<f2>...*XX` reply.
49	fn print_reg_fields(reply: &str) {
50	    let body = reply.trim_start_matches('$');
51	    let body = body.split('*').next().unwrap_or(body);
52	    let parts: Vec<&str> = body.split(',').collect();
53	    match parts.as_slice() {
54	        [_, id, fields @ ..] if !fields.is_empty() => {
55	            println!("register {id}: {fields:?}");
56	        }
57	        [_, id] => println!("register {id}: (no fields)"),
58	        _ => println!("(unrecognized reply)"),
59	    }
60	}
61	
62	/// Write the device's current settings to non-volatile memory (`$VNWNV`) so
63	/// they survive a power cycle. Shared by the `set-*` verbs' `--persist`.
64	fn save_to_flash<S: std::io::Read + std::io::Write>(
65	    port: &mut S,
66	    no_reply: &str,
67	) -> Result<(), Box<dyn std::error::Error>> {
68	    let confirm = transact_retry(
69	        port,
70	        &build_command("VNWNV"),
71	        5,
72	        |l| l.starts_with("$VNWNV"),
73	        no_reply,
74	    )?;
75	    println!("RX: {confirm}");
76	    println!("Settings written to non-volatile memory.");
77	    Ok(())
78	}
79	
80	/// Print a one-line summary of a binary-output (register 75) config.
81	///
82	/// - State is the streaming port (`off`, `port N`, or both).
83	/// - Rate is `800 / divisor`; the Common fields come from the mask.
84	fn report_bin_config(r: &Reg75) {
85	    let state = match r.async_mode {
86	        0 => "off".to_string(),
87	        3 => "on (both ports)".to_string(),
88	        p => format!("on (port {p})"),
89	    };
90	    let rate = if r.divisor > 0 {
91	        format!("{} Hz", 800 / r.divisor as u32)
92	    } else {
93	        "rate unset".to_string()
94	    };
95	    let names: Vec<&str> = fields_from_mask(r.mask).iter().map(|f| f.name).collect();
96	    println!(
97	        "Binary output: {state}, {rate} (divisor {}), Common{names:?}.",
98	        r.divisor
99	    );
100	}
101	
102	/// Parse args, open the serial port, and dispatch the requested command.
103	pub fn run() -> Result<(), Box<dyn std::error::Error>> {
104	    let (config, command) = match parse_args(std::env::args().skip(1)) {
105	        Ok(parsed) => parsed,
106	        Err(e) => {
107	            // Print only the error (plus a pointer) — not the whole help, which
108	            // on a small terminal scrolls the error itself off the top.
109	            eprintln!("error: {e}");
110	            eprintln!("run `rw-vn100 --help` for usage");
111	            std::process::exit(2);
112	        }
113	    };
114	
115	    if let Command::Help = command {
116	        print!("{}", help_text());
117	        return Ok(());
