/// - `RW_VN100_CAPTURE=<path>` set → records every raw byte read into memory
///   and writes it to `<path>` at the end. Unset → the read path is unchanged.
pub fn bench<S: Read>(
    port: &mut S,
    baud: u32,
    secs: u64,
) -> Result<(), Box<dyn std::error::Error>> {
    println!("Measuring the live stream for {secs}s (passive — no device writes)...");
