        let mut cap = CaptureReader {
            inner: port,
            sink: Vec::new(),
        };
        let st = measure(&mut cap, secs)?;
        std::fs::write(&path, &cap.sink)?;
        println!("Captured {} raw bytes to {path}.", cap.sink.len());
        st
    } else {
